appsmith.onReady(() => {
  generateRemediations();
});
appsmith.onModelChange(() => {
  generateRemediations();
});
function generateRemediations() {
  const model = appsmith.model || {};
  const cookies = model.cookies || [];
  const logs = model.networkEvents || [];
  const scripts = model.scriptData || {};
  let actions = [];
  let criticalCount = 0;
  let highCount = 0;

  // --- 1. Network Logs Analysis (Shadow AI) ---
  const unsanctionedAI = ["api.openai.com", "claude.ai", "mistral.ai", "googletagmanager.com"];
  let uniqueDomains = new Set();
  if (Array.isArray(logs)) {
    logs.forEach(event => {
      if (event.method === "Network.requestWillBeSent") {
        const urlStr = event.params.request.url || "";
        try {
          const domain = new URL(urlStr).hostname;
          if (unsanctionedAI.some(ai => domain.includes(ai)) && !uniqueDomains.has(domain)) {
            uniqueDomains.add(domain);
            actions.push({
              severity: "CRITICAL",
              priority: 1,
              evidence: `Unsanctioned AI Egress (${domain})`,
              recommendation: `Audit client-side network routing. Remove or restrict direct egress paths to ${domain} to prevent unsanctioned model ingestion.`
            });
            criticalCount++;
          }
        } catch (e) {}
      }
    });
  }

  // --- 2. Script Data Analysis (Client-Side Logic) ---
  const rootKey = Object.keys(scripts)[0];
  const scriptsMap = rootKey ? scripts[rootKey] : {};
  Object.entries(scriptsMap).forEach(([url, info]) => {
    const fileName = url.split('/').pop() || "unknown_asset.js";
    const sensitive = info["sensitive PIIs"] || [];
    const pii = info.PIIs || [];
    if (sensitive.length > 0) {
      actions.push({
        severity: "CRITICAL",
        priority: 2,
        evidence: `Sensitive Logic Signal in ${fileName}`,
        recommendation: `Refactor source code to remove hardcoded sensitive identifiers (${sensitive[0]}). Implement secure backend state management.`
      });
      criticalCount++;
    } else if (pii.length > 0 && actions.length < 15) {
      actions.push({
        severity: "HIGH",
        priority: 3,
        evidence: `PII Marker Exposure in ${fileName}`,
        recommendation: `Review ${fileName} to ensure PII markers (${pii[0]}) are not unnecessarily exposed to DOM scraping or unverified third-party scripts.`
      });
      highCount++;
    }
  });

  // --- 3. Cookie Analysis (Egress Signals) ---
  if (Array.isArray(cookies)) {
    let thirdPartyCookies = cookies.filter(c => c.thirdParty);
    if (thirdPartyCookies.length > 0) {
      // Aggregate rather than creating a row for every single cookie
      actions.push({
        severity: "HIGH",
        priority: 4,
        evidence: `${thirdPartyCookies.length} High Egress Trackers Detected`,
        recommendation: `Update Data Governance frameworks and CMP (Consent Management Platform) to explicitly declare routing paths for tracking keys like '${thirdPartyCookies[0].name}'.`
      });
      highCount++;
    }
    let exposedJsCookies = cookies.filter(c => !c.httpOnly);
    if (exposedJsCookies.length > 0 && actions.length < 15) {
      actions.push({
        severity: "MODERATE",
        priority: 5,
        evidence: `${exposedJsCookies.length} JS-Accessible Storage Keys`,
        recommendation: `Apply the 'HttpOnly' flag to authentication and session keys (e.g., '${exposedJsCookies[0].name}') to reduce client-side scraping risk.`
      });
    }
  }

  // --- UI Rendering ---
  document.getElementById('critical-count').textContent = criticalCount;
  document.getElementById('high-count').textContent = highCount;
  const statusEl = document.getElementById('remediation-status');
  if (actions.length === 0) {
    statusEl.textContent = "Baseline Verified";
    statusEl.style.color = "#27ae60";
  } else {
    statusEl.textContent = "Action Required";
    statusEl.style.color = "#c0392b";
  }

  // Sort by priority and cap at 10 items
  actions.sort((a, b) => a.priority - b.priority);
  const top10 = actions.slice(0, 10);
  const tbody = document.getElementById('remediation-body');
  tbody.innerHTML = "";
  if (top10.length === 0) {
    tbody.innerHTML = `<tr><td colspan="4" style="text-align:center; padding: 2rem; color: #7f8c8d;">No priority risk reductions identified in the current baseline data. Ensure telemetry logs are populated.</td></tr>`;
    return;
  }
  top10.forEach((item, index) => {
    const row = document.createElement('tr');
    const bgBadge = item.severity === 'CRITICAL' ? '#fce4e4' : item.severity === 'HIGH' ? '#fcf3cf' : '#e8f8f5';
    const textBadge = item.severity === 'CRITICAL' ? '#c0392b' : item.severity === 'HIGH' ? '#d35400' : '#1e8449';
    row.innerHTML = `
            <td style="padding: 12px; border-bottom: 1px solid #eee; color: #7f8c8d; font-weight: bold;">${index + 1}</td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;">
                <span style="padding: 4px 8px; border-radius: 12px; font-size: 0.75rem; font-weight: bold; background-color: ${bgBadge}; color: ${textBadge};">${item.severity}</span>
            </td>
            <td style="padding: 12px; border-bottom: 1px solid #eee; font-family: monospace; font-size: 0.85rem; color: #d35400;">
                ${item.evidence}
            </td>
            <td style="padding: 12px; border-bottom: 1px solid #eee; color: #2c3e50; line-height: 1.4;">
                ${item.recommendation}
            </td>
        `;
    tbody.appendChild(row);
  });
}

